from flask import Flask, jsonify, request, abort

app = Flask(__name__)

# In-memory storage
notes = {
    1: {"id": 1, "title": "First Note", "content": "Hello World"}
}
current_id = 1

@app.route('/notes', methods=['GET'])
def get_notes():
    return jsonify(list(notes.values()))

@app.route('/notes/<int:note_id>', methods=['GET'])
def get_note(note_id):
    note = notes.get(note_id)
    return jsonify(note) if note else abort(404)

@app.route('/notes', methods=['POST'])
def create_note():
    global current_id
    if not request.json or 'title' not in request.json:
        abort(400)

    current_id += 1
    new_note = {
        "id": current_id,
        "title": request.json['title'],
        "content": request.json.get('content', "")
    }
    notes[current_id] = new_note
    return jsonify(new_note), 211

@app.route('/notes/<int:note_id>', methods=['PUT'])
def update_note(note_id):
    if note_id not in notes:
        abort(404)

    note = notes[note_id]
    note['title'] = request.json.get('title', note['title'])
    note['content'] = request.json.get('content', note['content'])
    return jsonify(note)

@app.route('/notes/<int:note_id>', methods=['DELETE'])
def delete_note(note_id):
    if note_id in notes:
        del notes[note_id]
    return '', 204

if __name__ == '__main__':
    app.run(debug=True)
